mapper.select:
SELECT id, organization_id, name, location, description, qr_code, created_at, updated_at, created_by
FROM boxes
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND organization_id = #{organizationId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

SELECT COUNT(*)
FROM boxes
WHERE organization_id = #{organizationId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

SELECT organization_id
FROM boxes
WHERE id = #{boxId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

mapper.update:
UPDATE boxes
SET name = #{name},
    location = #{location},
    description = #{description},
    updated_at = #{updatedAt}
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND organization_id = #{organizationId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

mapper.delete:
DELETE FROM boxes
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND organization_id = #{organizationId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
